import React, { useState } from 'react';
import { Modal, Button, Form, ProgressBar } from 'react-bootstrap';
import { toast } from 'react-toastify';
import { updateDocument } from '../api';
import { useAuth } from '../contexts/AuthContext';

const UpdateDocumentModal = ({ show, onHide, documentId, onUpdated }) => {
  const [file, setFile] = useState(null);
  const [reason, setReason] = useState('');
  const [uploading, setUploading] = useState(false);
  const [progress, setProgress] = useState(0);
  const { user } = useAuth();

  const handleFileChange = (e) => {
    if (e.target.files && e.target.files.length > 0) {
      setFile(e.target.files[0]);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!file) {
      toast.error('Please select a file to upload');
      return;
    }
    setUploading(true);
    setProgress(0);
    try {
      const fd = new FormData();
      fd.append('file', file);
      fd.append('reason', reason);
      fd.append('uploadedBy', user?.name || user?.username || 'System');

      // Simple client-side progress simulation for UX
      const progInterval = setInterval(() => {
        setProgress(p => {
          if (p >= 90) {
            clearInterval(progInterval);
            return p;
          }
          return p + 10;
        });
      }, 200);

      await updateDocument(documentId, fd);
      setProgress(100);
      toast.success('Document updated successfully');
      setFile(null);
      setReason('');
      if (onUpdated) onUpdated();
      onHide();
    } catch (err) {
      console.error('Update error:', err);
      const msg = err.response?.data?.message || err.message || 'Error updating document';
      toast.error(msg);
    } finally {
      setUploading(false);
      setProgress(0);
    }
  };

  return (
    <Modal show={show} onHide={onHide} centered>
      <Modal.Header closeButton>
        <Modal.Title>Update Document</Modal.Title>
      </Modal.Header>
      <Modal.Body>
        <Form onSubmit={handleSubmit}>
          <Form.Group className="mb-3">
            <Form.Label>New File</Form.Label>
            <Form.Control type="file" accept=".pdf,.docx,.jpg,.jpeg,.png" onChange={handleFileChange} />
          </Form.Group>
          <Form.Group className="mb-3">
            <Form.Label>Reason for Update (optional)</Form.Label>
            <Form.Control as="textarea" rows={3} value={reason} onChange={(e) => setReason(e.target.value)} />
          </Form.Group>
          {uploading && (
            <div className="mb-3">
              <ProgressBar now={progress} animated />
            </div>
          )}
          <div className="d-flex justify-content-end gap-2">
            <Button variant="secondary" onClick={onHide} disabled={uploading}>Cancel</Button>
            <Button variant="primary" type="submit" disabled={uploading}>Update</Button>
          </div>
        </Form>
      </Modal.Body>
    </Modal>
  );
};

export default UpdateDocumentModal;
